    private fun sortInfoFromCollection(
        col: com.ichi2.libanki.Collection,
        preferences: SharedPreferences,
        mode: CardsOrNotes = cardsOrNotes
    ): Pair<SortType, Boolean> {
        val colOrder = col.config.get<String>(sortTypeConfigKey(mode))
        var type = SortType.entries.firstOrNull { it.ankiSortType == colOrder } ?: SortType.NO_SORTING
        if (type == SortType.SORT_FIELD && preferences.getBoolean("cardBrowserNoSorting", false)) {
            type = SortType.NO_SORTING
        }
        val orderBackwards = col.config.get(sortBackwardsConfigKey(mode)) ?: false
        return type to orderBackwards
