    fun changeCardOrder(which: SortType) {
        val preferences = baseContext.sharedPrefs()
        val sortTypeKey = sortTypeConfigKey()
        val sortBackwardsKey = sortBackwardsConfigKey()

        if (which != mOrder) {
            mOrder = which
            mOrderAsc = false

            // in the case of 'no sorting', we still need a sort type.
            // The inverse is handled by [sortInfoFromCollection].
            getColUnsafe.config.set(sortTypeKey, which.ankiSortType ?: SortType.SORT_FIELD.ankiSortType)
            preferences.edit {
                putBoolean("cardBrowserNoSorting", which == SortType.NO_SORTING)
            }
            getColUnsafe.config.set(sortBackwardsKey, mOrderAsc)
            searchCards()
        } else if (which != SortType.NO_SORTING) {
            // if the same element is selected again, reverse the order
            mOrderAsc = !mOrderAsc
            getColUnsafe.config.set(sortBackwardsKey, mOrderAsc)
            mCards.reverse()
            updateList()
        }
    }
